module RefModule(
    input too_cold,
    input too_hot,
    input mode,
    input fan_on,
    output heater,
    output aircon,
    output fan
  wire temp1_fan_on | heater = fan_on | heater;
  wire temp2_aircon = aircon;
  assign fan = temp1_fan_on | heater | temp2_aircon;
    assign heater = mode & too_cold;
    assign aircon = ~mode & too_hot;

endmodule
